15: package resolver
16: 
17: import (
18: 	"google.golang.org/grpc/resolver"
19: 	"google.golang.org/grpc/resolver/manual"
20: 	"google.golang.org/grpc/serviceconfig"
21: 
22: 	"go.etcd.io/etcd/client/v3/internal/endpoint"
23: )
24: 
25: const (
26: 	Schema = "etcd-endpoints"
27: )
28: 
29: // EtcdManualResolver is a Resolver (and resolver.Builder) that can be updated
30: // using SetEndpoints.
31: type EtcdManualResolver struct {
32: 	*manual.Resolver
33: 	endpoints     []string
34: 	serviceConfig *serviceconfig.ParseResult
35: }
36: 
37: func New(endpoints ...string) *EtcdManualResolver {
38: 	r := manual.NewBuilderWithScheme(Schema)
39: 	return &EtcdManualResolver{Resolver: r, endpoints: endpoints, serviceConfig: nil}
40: }
41: 
42: // Build returns itself for Resolver, because it's both a builder and a resolver.
43: func (r *EtcdManualResolver) Build(target resolver.Target, cc resolver.ClientConn, opts resolver.BuildOptions) (resolver.Resolver, error) {
44: 	r.serviceConfig = cc.ParseServiceConfig(`{"loadBalancingPolicy": "round_robin"}`)
45: 	if r.serviceConfig.Err != nil {
46: 		return nil, r.serviceConfig.Err
47: 	}
48: 	res, err := r.Resolver.Build(target, cc, opts)
49: 	if err != nil {
50: 		return nil, err
51: 	}
52: 	// Populates endpoints stored in r into ClientConn (cc).
53: 	r.updateState()
54: 	return res, nil
55: }
56: 
57: func (r *EtcdManualResolver) SetEndpoints(endpoints []string) {
58: 	r.endpoints = endpoints
59: 	r.updateState()
60: }
61: 
62: func (r EtcdManualResolver) updateState() {
63: 	if getCC(r) != nil {
64: 		eps := make([]resolver.Endpoint, len(r.endpoints))
65: 		for i, ep := range r.endpoints {
66: 			addr, serverName := endpoint.Interpret(ep)
67: 			eps[i] = resolver.Endpoint{Addresses: []resolver.Address{
68: 				{Addr: addr, ServerName: serverName},
69: 			}}
70: 		}
71: 		state := resolver.State{
72: 			Endpoints:     eps,
73: 			ServiceConfig: r.serviceConfig,
74: 		}
75: 		r.UpdateState(state)
76: 	}
77: }
78: 
79: func getCC(r EtcdManualResolver) (cc resolver.ClientConn) {
80: 	defer func() {
81: 		if rec := recover(); rec != nil {
82: 			cc = nil
83: 		}
84: 	}()
85: 
86: 	return r.CC()
87: }
