377: func authority(endpoint string) string {
378: 	spl := strings.SplitN(endpoint, "://", 2)
379: 	if len(spl) < 2 {
380: 		if strings.HasPrefix(endpoint, "unix:") {
381: 			return endpoint[len("unix:"):]
382: 		}
383: 		if strings.HasPrefix(endpoint, "unixs:") {
384: 			return endpoint[len("unixs:"):]
385: 		}
386: 		return endpoint
387: 	}
388: 	return spl[1]
389: }
