535: // roundRobinQuorumBackoff retries against quorum between each backoff.
536: // This is intended for use with a round robin load balancer.
537: func (c *Client) roundRobinQuorumBackoff(waitBetween time.Duration, jitterFraction float64) backoffFunc {
538: 	return func(attempt uint) time.Duration {
539: 		// after each round robin across quorum, backoff for our wait between duration
540: 		n := uint(len(c.Endpoints()))
541: 		quorum := (n/2 + 1)
542: 		if attempt%quorum == 0 {
543: 			c.GetLogger().Debug("backoff", zap.Uint("attempt", attempt), zap.Uint("quorum", quorum), zap.Duration("waitBetween", waitBetween), zap.Float64("jitterFraction", jitterFraction))
544: 			return jitterUp(waitBetween, jitterFraction)
545: 		}
546: 		c.GetLogger().Debug("backoff skipped", zap.Uint("attempt", attempt), zap.Uint("quorum", quorum))
547: 		return 0
548: 	}
549: }
